import React, { useState, useEffect } from "react";
import axios from "axios";
import { useNavigate } from "react-router-dom";

export default function Categorias() {
  const [categorias, setCategorias] = useState([]);
  const [categoriaActual, setCategoriaActual] = useState({
    id: null,
    nombre: "",
    descripcion: "",
  });

  const [showModal, setShowModal] = useState(false);
  const [modoEdicion, setModoEdicion] = useState(false);
  const [busqueda, setBusqueda] = useState("");

  const navigate = useNavigate();

  // 📄 Paginación
  const [paginaActual, setPaginaActual] = useState(1);
  const categoriasPorPagina = 6;

  useEffect(() => {
    obtenerCategorias();
  }, []);

  // ✅ SOLO id, nombre, descripcion (sin mezclas)
  const obtenerCategorias = async () => {
    try {
      const res = await axios.get("http://localhost:5000/api/categorias");
      setCategorias(res.data);
    } catch (error) {
      console.error("❌ Error al obtener categorías:", error);
    }
  };

  const handleChange = (e) => {
    setCategoriaActual({
      ...categoriaActual,
      [e.target.name]: e.target.value,
    });
  };

  const abrirModalAgregar = () => {
    setCategoriaActual({ id: null, nombre: "", descripcion: "" });
    setModoEdicion(false);
    setShowModal(true);
  };

  const abrirModalEditar = (cat) => {
    setCategoriaActual(cat);
    setModoEdicion(true);
    setShowModal(true);
  };

  const guardarCategoria = async (e) => {
    e.preventDefault();

    try {
      if (modoEdicion) {
        await axios.put(
          `http://localhost:5000/api/categorias/${categoriaActual.id}`,
          categoriaActual
        );
      } else {
        await axios.post(
          "http://localhost:5000/api/categorias",
          categoriaActual
        );
      }

      setShowModal(false);
      obtenerCategorias();
    } catch (error) {
      console.error("❌ Error al guardar categoría:", error);
    }
  };

  const eliminarCategoria = async (id) => {
    if (!window.confirm("¿Eliminar esta categoría?")) return;

    try {
      await axios.delete(`http://localhost:5000/api/categorias/${id}`);
      obtenerCategorias();
    } catch (error) {
      console.error("❌ Error al eliminar categoría:", error);
    }
  };

  // 🔎 Filtro
  const categoriasFiltradas = categorias.filter((c) =>
    c.nombre.toLowerCase().includes(busqueda.toLowerCase())
  );

  // 📄 Paginación
  const inicio = (paginaActual - 1) * categoriasPorPagina;
  const categoriasPaginadas = categoriasFiltradas.slice(
    inicio,
    inicio + categoriasPorPagina
  );

  return (
    <div className="container mt-5">
      <div className="d-flex justify-content-between mb-4">
        <input
          className="form-control w-50"
          placeholder="Buscar categoría..."
          value={busqueda}
          onChange={(e) => {
            setBusqueda(e.target.value);
            setPaginaActual(1);
          }}
        />

        <button className="btn btn-success" onClick={abrirModalAgregar}>
          ➕ Agregar Categoría
        </button>
      </div>

      <div className="row">
        {categoriasPaginadas.map((cat) => (
          <div key={cat.id} className="col-md-4 mb-4">
            <div
              className="card shadow h-100"
              style={{ cursor: "pointer" }}
              onClick={() => navigate(`/categorias/${cat.id}/productos`)}
            >
              <div className="card-body">
                <h5 className="text-center">{cat.nombre}</h5>

                <div className="d-flex justify-content-between mt-3">
                  <button
                    className="btn btn-warning btn-sm"
                    onClick={(e) => {
                      e.stopPropagation();
                      abrirModalEditar(cat);
                    }}
                  >
                    ✏️ Editar
                  </button>

                  <button
                    className="btn btn-danger btn-sm"
                    onClick={(e) => {
                      e.stopPropagation();
                      eliminarCategoria(cat.id);
                    }}
                  >
                    🗑️ Eliminar
                  </button>
                </div>
              </div>
            </div>
          </div>
        ))}
      </div>

      {/* MODAL */}
      {showModal && (
        <div
          className="modal fade show"
          style={{ display: "block", background: "rgba(0,0,0,.6)" }}
        >
          <div className="modal-dialog modal-dialog-centered">
            <div className="modal-content p-4">
              <h5>{modoEdicion ? "Editar" : "Nueva"} Categoría</h5>

              <form onSubmit={guardarCategoria}>
                <input
                  name="nombre"
                  className="form-control mb-2"
                  placeholder="Nombre"
                  value={categoriaActual.nombre}
                  onChange={handleChange}
                  required
                />

                <textarea
                  name="descripcion"
                  className="form-control mb-3"
                  placeholder="Descripción"
                  value={categoriaActual.descripcion}
                  onChange={handleChange}
                />

                <div className="text-end">
                  <button
                    type="button"
                    className="btn btn-secondary me-2"
                    onClick={() => setShowModal(false)}
                  >
                    Cancelar
                  </button>
                  <button className="btn btn-primary">Guardar</button>
                </div>
              </form>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}
